SELECT COUNT(breach_id) AS total_breaches
FROM breaches
WHERE entity_id = 1;

SELECT breach_id, breach_description
FROM breaches
WHERE strftime('%Y', breach_date) = '2009';

SELECT entity_id
FROM breach_statistics
ORDER BY total_breaches DESC;

SELECT entity_name
FROM covered_entities
WHERE state = 'California';

SELECT entity_name
FROM covered_entities
ORDER BY entity_name ASC;

SELECT entity_id, COUNT(breach_id) AS total_breaches
FROM breaches
GROUP BY entity_id;

SELECT individual_name
FROM individuals_affected
WHERE breach_id = 1;

SELECT COUNT(individual_id) AS total_affected_individuals
FROM individuals_affected
WHERE breach_id = 1;

SELECT SUM(individuals_affected) AS total_individuals_affected
FROM covered_entities
WHERE entity_id = 0;

SELECT associate_name
FROM business_associates
WHERE business_associate_type = 'IT Services';
